+
+#include <vector>
+
+namespace iiwa_interface{
+//forward declaration
+class TCPConnection;
+
+enum CommandState: char{
+  ACCEPTED = 1,
+  REJECTED = 2,
+  UNKNOWN = 3,
+  ERROR_SIGNAL = 4
+};
+
+enum CommandID: char{
+  CONNECT = 1,
+  DISCONNECT = 2,
+  START_FRI = 3,
+  END_FRI = 4,
+  ACTIVATE_CONTROL = 5,
+  DEACTIVATE_CONTROL = 6,
+  GET_FRI_CONFIG = 7,
+  SET_FRI_CONFIG = 8,
+  GET_CONTROL_MODE = 9,
+  SET_CONTROL_MODE = 10
+};
+
+enum CommandSuccess: char{
+  SUCCESS = 1,
+  NO_SUCCESS = 2
+};
+
+enum ControlModeID: char{
+  POSITION = 1,
+  JOINT_IMPEDANCE = 2
+};
+
+
+class RobotManager{
+  bool connect(const char* server_addr, int server_port);
+  bool disconnect();
+  bool startFRI();
+  bool endFRI();
+  bool activateControl();
+  bool deactivateControl();
+  bool setControlMode(ControlModeID control_mode_id);
+  //bool getControlMode();
+  bool setFRIConfig();
+  //bool getFRIConfig();
+
+private:
+  TCPConnection tcp_connection_;
+
+
+  void handleReceivedTCPData(const std::vector<char>& data);
+  void connectionLostCallback();
+
+  CommandState last_command_state_;
+  CommandID last_command_id_;
+  CommandSuccess last_command_success_;
+
+  void sendCommand(CommandID command_id);
+  void wait();
+  bool assertLastCommandSuccess(CommandID command_id);
+  bool sendCommandAndWait(CommandID command_id);
+
+};
+
+
+
